import{_ as e}from"./chunks/20230127015634.891e424c.js";import{_ as l,o as t,c as o,a}from"./app.a903291e.js";const r="/assets/20230127012501.ae9795e3.png",i="/assets/20230127012745.3b5dda70.png",s="/assets/20230127012758.21643493.png",n="/assets/20230127013030.78e6f9d7.png",f=JSON.parse('{"title":"\u4F7F\u7528Studio One\u7684\u9891\u8C31\u4EEA","description":"","frontmatter":{"tittle":"\u4F7F\u7528Studio One\u7684\u9891\u8C31\u4EEA","date":"2023/01/27","tags":["\u6570\u5B57\u97F3\u9891\u5DE5\u4F5C\u7AD9(DAW)","\u5FEB\u901F\u5085\u91CC\u53F6\u53D8\u6362","\u6CE2\u5F62\u5206\u6790","\u4FE1\u53F7\u7CFB\u7EDF","\u6A21\u62DF\u7535\u8DEF"]},"headers":[{"level":2,"title":"FFT","slug":"fft","link":"#fft","children":[]},{"level":2,"title":"Level Range","slug":"level-range","link":"#level-range","children":[{"level":3,"title":"\u6539\u53D8Level","slug":"\u6539\u53D8level","link":"#\u6539\u53D8level","children":[]}]},{"level":2,"title":"Peak Hold","slug":"peak-hold","link":"#peak-hold","children":[]},{"level":2,"title":"Smooth","slug":"smooth","link":"#smooth","children":[]},{"level":2,"title":"Slope","slug":"slope","link":"#slope","children":[]}],"relativePath":"Article/\u4F7F\u7528Studio One\u7684\u9891\u8C31\u4EEA.md"}'),d={name:"Article/\u4F7F\u7528Studio One\u7684\u9891\u8C31\u4EEA.md"},p=a('<h1 id="\u4F7F\u7528studio-one\u7684\u9891\u8C31\u4EEA" tabindex="-1">\u4F7F\u7528Studio One\u7684\u9891\u8C31\u4EEA <a class="header-anchor" href="#\u4F7F\u7528studio-one\u7684\u9891\u8C31\u4EEA" aria-hidden="true">#</a></h1><h2 id="fft" tabindex="-1">FFT <a class="header-anchor" href="#fft" aria-hidden="true">#</a></h2><hr><p>\u5728\u8BB0\u5F55\u5230\u65F6\u57DF\u4FE1\u53F7\u540E\uFF0C\u9891\u8C31\u4EEA\u4F1A\u5BF9\u65F6\u57DF\u4FE1\u53F7\u8FDB\u884C<strong>\u5FEB\u901F\u5085\u91CC\u53F6\u53D8\u6362</strong>\u83B7\u5F97\u5B83\u7684<strong>\u9891\u57DF\u66F2\u7EBF\uFF08FFT Curve\uFF09</strong></p><ul><li>\u5BF9\u4E8E\u4E00\u4E2A\u5468\u671F\u6027\u7684\u4FE1\u53F7\u6CE2\u5F62\uFF0C\u603B\u80FD\u8BA4\u4E3A\u5B83\u662F\u7531\u591A\u4E2A\u9891\u7387\u3001\u5E45\u503C\u3001\u76F8\u4F4D\u4E0D\u540C\u7684\u6B63\u5F26/\u4F59\u5F26\u6CE2\u7684\u7EBF\u6027\u7EC4\u5408</li><li>\u901A\u8FC7\u5FEB\u901F\u5085\u91CC\u53F6\u53D8\u6362\u53EF\u4EE5\u5F97\u5230\u4E00\u4E2A<strong>\u9891\u7387\u54CD\u5E94\u66F2\u7EBF</strong>\uFF0C\u63CF\u8FF0\u8FD9\u4E2A\u65F6\u57DF\u4FE1\u53F7\u4E2D<strong>\u4E0D\u540C\u9891\u7387\u7684\u6CE2\u5F62\u6240\u5360\u7684\u6BD4\u4F8B</strong></li></ul><p>\u5BF9\u4E8E\u4E50\u5668\u800C\u8A00\uFF0C\u5F39\u594F\u67D0\u4E2A\u5355\u97F3\uFF08\u5982440Hz\u7684A4\uFF09\uFF0C\u83B7\u53D6\u5176\u9891\u54CD\u66F2\u7EBF\uFF0C\u4F1A\u53D1\u73B0\u4E3B\u8981\u7684\u9891\u7387\u7EC4\u6210\uFF08\u5728\u9891\u57DF\u66F2\u7EBF\u4E2D\u8868\u73B0\u4E3A\u7A81\u51FA\u7684\u5C16\u5CF0\uFF09\u5305\u62EC\u5176\u57FA\u97F3\uFF08440Hz\uFF09\u548C\u6CDB\u97F3/\u8C10\u6CE2\uFF08440Hz\u7684\u6B63\u6574\u6570\u500D\u9891\u7387\uFF0C\u5982880Hz-\u4E00\u6B21\u6CDB\u97F3\u30011320Hz-\u4E8C\u6B21\u6CDB\u97F3\u7B49\uFF09\uFF0C\u57FA\u97F3\u548C\u4E0D\u540C\u9891\u7387\u7684\u6CDB\u97F3\u7684\u7EC4\u6210\u6BD4\u4F8B\u51B3\u5B9A\u4E86\u4E50\u5668\u7684\u97F3\u8272</p><h2 id="level-range" tabindex="-1">Level Range <a class="header-anchor" href="#level-range" aria-hidden="true">#</a></h2><hr><p>\u5BF9\u4E8E\u6570\u5B57\u97F3\u9891\u5E38\u7528\u7684dbFS\u57FA\u51C6\uFF0C\u8981\u6839\u636E\u4E8B\u5148\u8BBE\u5B9A\u597D\u7684\u91C7\u6837\u7CBE\u5EA6\u6765\u8BBE\u7F6E\u91CF\u7A0B\uFF08\u5F53\u524D\u91C7\u6837\u7CBE\u5EA6\u4E0B\u7684\uFF09\u624D\u80FD\u5F97\u5230\u6B63\u786E\u7684\u9891\u54CD\u66F2\u7EBF</p><p>FFT\u5904\u7406\u540E\u7684\u9891\u57DF\u66F2\u7EBF\u5B9E\u9645\u4E0A\u662F\u4ECE\u4E00\u6761\u4ECE\u67D0\u4E2ALevel\u4E3A\u8D1F\u5206\u8D1D\uFF08\u57FA\u4E8EdBFS\u57FA\u51C6\uFF09\u7684\u201C<strong>\u6709\u6548\u7535\u5E73\u7EBF</strong>\u201D\uFF08\u5728\u91C7\u6837\u7CBE\u5EA6\u662F16bit\u7684\u60C5\u51B5\u4E0B\uFF0C\u8FD9\u4E2A\u503C\u5C31\u662F-96dB\uFF09\u7684\u6A2A\u7EBF\u5F00\u59CB\u62DF\u5408\u7684\uFF0C\u5F53\u8BB0\u5F55\u5230\u7684\u4FE1\u53F7\u6CE2\u5F62\u5E45\u503C\u5927\u4E8E\u8FD9\u4E2A<strong>\u6709\u6548\u7535\u5E73\u7EBF</strong>\u65F6\uFF0C\u624D\u4F1A\u88AB\u9891\u8C31\u4EEA\u89C6\u4F5C\u6709\u6548\u4FE1\u53F7\u5E76\u8FDB\u884C\u5904\u7406</p><h3 id="\u6539\u53D8level" tabindex="-1">\u6539\u53D8Level <a class="header-anchor" href="#\u6539\u53D8level" aria-hidden="true">#</a></h3><p>\u4FEE\u6539Level Range\u540E\uFF0C\u5B9E\u9645\u4E0A\u4E5F\u4F1A\u6539\u53D8\u4E0A\u8FF0\u8FD9\u6761\u201C\u6A2A\u7EBF\u201D\u7684\u4F4D\u7F6E\uFF0C\u5728\u6539\u53D8Level Range\u540E\uFF0C\u8FD9\u6761\u66F2\u7EBF\u56E0\u4E3A\u8FD8\u5BF9\u5E94\u7740\u539F\u6765\u7684\u7EB5\u5750\u6807\u4F1A\u7AD6\u76F4\u5E73\u79FB\u4E00\u6BB5\u8DDD\u79BB\uFF0C\u4F46\u662F\u8FD9\u4E2A\u65F6\u5019\u8FD9\u6761\u66F2\u7EBF<strong>\u5DF2\u7ECF\u4E0D\u518D\u51C6\u786E\uFF0C\u9700\u8981\u820D\u5F03\u4E86</strong></p><p>\u4F8B\u5982\uFF0C\u5F53\u7528\u9891\u8C31\u4EEA\u8BB0\u5F55\u7684\u52A8\u6001\u8303\u56F4\u8F83\u5C0F\uFF08\u5982-48db\uFF09\u65F6\uFF0C\u5F80\u5F80\u5F97\u5230\u7684\u662F\u4E00\u4E2A\u5CF0\u503C\u6CE2\u52A8\u5F88\u5C0F\u751A\u81F3\u63A5\u8FD1\u4E8E\u5E73\u76F4\u6A2A\u7EBF\u7684\u4E0D\u51C6\u786E\u7684\u9891\u57DF\u66F2\u7EBF\uFF08\u56E0\u4E3A\u6B64\u65F6\u7684\u4FE1\u53F7\u5E45\u5EA6\u8FD8\u662F\u57FA\u672C\u5C0F\u4E8E\u6D4B\u91CF\u7684\u6700\u5C0F\u503C\uFF09\uFF0C\u4F46\u6B64\u65F6\u7684<strong>\u6709\u6548\u7535\u5E73\u7EBF</strong>\u662F-48db</p><p>\u5F53\u5C06\u52A8\u6001\u8303\u56F4\u6539\u5927\uFF08\u5982-144db\uFF09\u65F6\uFF0C\u8FD9\u6BB5\u8F83\u4E3A\u6241\u5E73\u7684\u66F2\u7EBF\u4F1A\u968F\u4E4B\u5411\u4E0A\u5E73\u79FB\u4E00\u6BB5\u8DDD\u79BB\uFF0C\u4F46\u662F\u8FD9\u6761\u66F2\u7EBF\u662F\u5728<strong>8bit\u91C7\u6837\u7CBE\u5EA6</strong>\u4E0B\u62DF\u5408\u51FA\u6765\u7684\u7ED3\u679C\uFF0C\u4E0D\u518D\u9002\u7528</p><ul><li>\u6700\u76F4\u767D\u7684\u4F8B\u5B50\u5C31\u662F\u5982\u679C\u53D6\u6D88\u8FD9\u6761\u66F2\u7EBF\u7684Peak Hold\uFF0C\u7136\u540E\u91CD\u65B0\u8BB0\u5F55\u7684\u8BDD\uFF0C\u4F1A\u5F97\u5230\u4E00\u4E2A\u66F4\u4E3A\u9661\u5CED\u7684\u66F2\u7EBF</li></ul><p><img src="'+r+'" alt=""> \u4E0A\u56FE\u767D\u8272\u7684\u66F2\u7EBF\u4E3A\u5728-48dB\u4E0B\u83B7\u5F97\u7684Peak Hold\u66F2\u7EBF\uFF0C\u5728\u5C06Level Range\u6539\u4E3A-144dB\u540E\uFF0C\u5176\u5F62\u72B6\u660E\u663E\u6709\u522B\u4E8E\u5B9E\u65F6\u7684\u9EC4\u8272\u66F2\u7EBF\uFF0C\u672C\u8D28\u4E0A\u662F\u4E24\u6761<strong>\u5728\u4E0D\u540C\u91C7\u6837\u7CBE\u5EA6\u6807\u51C6\u4E0B\u83B7\u5F97\u7684\u66F2\u7EBF</strong></p><ul><li>\u4ECE\u8FD9\u6761\u66F2\u7EBF\u4E5F\u80FD\u770B\u51FA\uFF0C\u5728\u4F4E\u91C7\u6837\u7CBE\u5EA6\u7684\u6807\u51C6\u4E0B\uFF0C\u4FE1\u53F7\u7684\u52A8\u6001\u8303\u56F4\u72ED\u5C0F\uFF0C\u66F4\u591A\u7684\u7EC6\u8282\u5F97\u4E0D\u5230\u4FDD\u7559</li></ul><h2 id="peak-hold" tabindex="-1">Peak Hold <a class="header-anchor" href="#peak-hold" aria-hidden="true">#</a></h2><hr><p>\u56E0\u4E3A\u65F6\u57DF\u4FE1\u53F7\u672C\u8EAB\u4E5F\u662F\u5728\u4E0D\u65AD\u53D8\u5316\u7684\uFF08\u968F\u65F6\u95F4\u8870\u51CF\uFF09\uFF0CFFT\u5F97\u5230\u7684\u9891\u57DF\u66F2\u7EBF\u4E5F\u662F\u4F1A\u968F\u4E4B\u53D8\u5316\u7684\uFF08\u968F\u4E4B\u8870\u51CF\uFF09</p><p>FFT Curve\u5B9E\u9645\u4E0A\u662F<strong>\u5B9E\u65F6\u7684\uFF0C\u4F1A\u968F\u65F6\u95F4\u8870\u51CF\u7684</strong>\uFF0C\u7ECF\u5E38\u51FA\u73B0\u8BB0\u5F55\u5230\u4FE1\u53F7\u540E\u8FD8\u6CA1\u6765\u5F97\u53CA\u5206\u6790\u5C31\u5DF2\u7ECF\u8870\u51CF\u6389\u7684\u60C5\u51B5\uFF0C\u8FD9\u65F6\u5019\u5C31\u9700\u8981\u9891\u8C31\u4EEA\u7684<strong>\u5CF0\u503C\u4FDD\u6301\u529F\u80FD</strong>\uFF08Peak Hold\uFF09</p><p>\u5728\u5173\u95EDSmooth\u7684\u60C5\u51B5\u4E0B\uFF0CPeak Hold\u5B9E\u9645\u4E0A\u5C31\u662F\u4FDD\u6301\u8BB0\u5F55\u5230\u7684\u6240\u6709\u9891\u57DF\u66F2\u7EBF\u7684\u6BCF\u4E2A\u9891\u6BB5\u90FD\u53D6\u5176\u6700\u5927\u503C\u83B7\u5F97\u7684<strong>\u79BB\u6563\u70B9</strong></p><ul><li>\u5728\u5F39\u594F\u5355\u97F3\u7684\u60C5\u51B5\u4E0B\uFF0CPeak Hold\u7684\u5F62\u72B6\u5B9E\u9645\u4E0A\u5C31\u662FFFT\u5F97\u5230\u7684\u6700\u5927\u9891\u57DF\u66F2\u7EBF</li><li>\u5728\u591A\u6B21\u5F39\u594F\u7684\u60C5\u51B5\u4E0B\uFF0CPeak Hold\u4F1A\u5F97\u5230\u4E00\u6761\u66F4\u4E3A\u5747\u8861\u7684\u9891\u57DF\u66F2\u7EBF</li></ul><p>\u8FD9\u4E2A\u529F\u80FD\u548CLevel Range\u662F\u606F\u606F\u76F8\u5173\u7684\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u539F\u59CB\u6570\u636E\u7684\u8BB0\u5F55\u5C31\u662F\u4ECELevel Range\u8BBE\u5B9A\u7684<strong>\u6709\u6548\u7535\u5E73\u7EBF</strong>\u5F00\u59CB\uFF0C\u9AD8\u4E8E\u8FD9\u4E2A\u7EBF\u7684\u4FE1\u53F7\u5E45\u503C\u88AB\u8BB0\u5F55\u4E0B\u6765\uFF08\u5982\u679C\u662FPeak Hold\u5219\u53D6\u6700\u5927\u503C\uFF09\uFF0C\u4ECE\u800C\u83B7\u5F97\u4E00\u7CFB\u5217\u79BB\u6563\u70B9\u2014\u2014<strong>\u6BCF\u4E2A\u9891\u7387\u4E0B\u7684\u6700\u5927\u7535\u5E73</strong></p><p><img src="'+e+'" alt=""></p><p>\u4E00\u4E2A\u7ECF\u8FC7Smooth\u5904\u7406\u8FC7\u7684\u5F39\u594FA4\u5355\u97F3\u7684\u9891\u57DF\u66F2\u7EBF\uFF0C\u4ECD\u7136\u53EF\u4EE5\u770B\u51FA\u6709\u6570\u4E2A\u7A81\u51FA\u7684\u5C16\u5CF0</p><ul><li>\u4E3A\u4E86\u6392\u9664\u8FC7\u8F7D\u7B49\u6548\u679C\u5668\u7684\u5F71\u54CD\uFF0C\u76F4\u63A5\u65C1\u901A\u4E86\u6548\u679C\u5668\u8FDB\u884C\u4FE1\u53F7\u91C7\u6837\uFF0C\u6240\u4EE5\u5728-96dB\u7684\u52A8\u6001\u4E0B\u5E45\u503C\u4ECD\u7136\u4E0D\u662F\u5F88\u5927</li><li>\u5F53\u7136\u5730\uFF0C\u8FD9\u51E0\u4E2A\u5C16\u5CF0\u7684\u9891\u6BB5\u5206\u522B\u5BF9\u5E94\u4E86A4\u7684\u57FA\u97F3\uFF08440Hz\uFF09\u4E0E\u5176\u8C10\u6CE2\uFF08880Hz\u30011320Hz\u7B49\uFF09</li></ul><h2 id="smooth" tabindex="-1">Smooth <a class="header-anchor" href="#smooth" aria-hidden="true">#</a></h2><hr><p>Smooth\u548CSlope\u4F1A\u5F71\u54CD\u6240\u6709FFT Curve\uFF08\u5305\u62ECPeak Hold\u66F2\u7EBF\u548CAverage\u66F2\u7EBF\uFF09</p><p>\u76F4\u63A5\u83B7\u5F97\u7684FFT Curve\uFF0C\u5176\u5B9E\u4F1A\u6BD4\u8F83\u5C16\u9510\u800C\u4E14\u6709\u591A\u4E2A\u660E\u663E\u7684\u5C16\u5CF0\uFF0C\u96BE\u4EE5\u5206\u6790\u548C\u67E5\u770B\uFF0C\u5F00\u542FSmooth\u540E\u4F1A\u5BF9\u5176\u8FDB\u884C\u66F2\u7EBF\u5E73\u6ED1\u5316\u5904\u7406\uFF0C\u83B7\u5F97\u4E00\u4E2A\u66F4\u6613\u4E8E\u8FA8\u8BC6\u7684\u66F2\u7EBF</p><p><img src="'+i+'" alt=""></p><p>\u6CA1\u6709\u5F00\u542FSmooth\u7684FFT Curve</p><p><img src="'+s+'" alt=""></p><p>\u5F00\u542FSmooth\u7684FFT Curve</p><h2 id="slope" tabindex="-1">Slope <a class="header-anchor" href="#slope" aria-hidden="true">#</a></h2><hr><p>\u5728\u7535\u8DEF\u7CFB\u7EDF\u4E2D\uFF0C\u7531\u4E8E\u7535\u8DEF\u7279\u6027\u7ECF\u5E38\u4F1A\u5F15\u5165\u7C89\u7EA2\u566A\u97F3\uFF08pink-noise\uFF09</p><ul><li>\u672C\u8D28\u662F\u5728\u5404\u9891\u6BB5\u4E0B\u529F\u7387\u76F8\u540C\u7684\u566A\u97F3\uFF0C\u4E0A\u6587\u63D0\u5230\u8FC7\u5BF9\u4E8E\u58F0\u97F3\u800C\u8A00\uFF0C\u6BCF\u9AD83dB\uFF0C\u58F0\u538B\u7EA7\u9AD81/\u6839\u53F72\u500D\uFF0C\u800C\u58F0\u529F\u7387\u6B63\u6BD4\u4E8E\u58F0\u538B\u7EA7\u5E73\u65B9\uFF0C\u5373\u58F0\u529F\u7387\u9AD82\u500D\uFF0C\u5BF9\u4E8E\u7C89\u7EA2\u566A\u97F3\u7684\u9891\u54CD\u56FE\uFF0C\u53EF\u4EE5\u5F97\u77E5\u662F\u4E00\u6761\u659C\u7387\u4E3A-3dB/\u4E8C\u500D\u9891\uFF08\u4E5F\u53EF\u4EE5\u8BF4-3dB/\u516B\u5EA6\u97F3\uFF09\u7684\u66F2\u7EBF</li></ul><p>\u5728FFT\u5F97\u5230\u7684\u9891\u54CD\u56FE\u4E2D\u4E3A\u4E86\u62B5\u6D88\u7C89\u7EA2\u566A\u97F3\u7684\u5E72\u6270\uFF0C\u5F80\u5F80\u4E5F\u8981\u5BF9\u66F2\u7EBF\u8FDB\u884C\u659C\u7387\u7684\u4FEE\u6B63\uFF08+3dB/Oct\uFF09</p><p><img src="https://upload.wikimedia.org/wikipedia/commons/7/7a/Pink_noise_spectrum.png" alt=""></p><p>\u7EF4\u57FA\u4E2D\u7ED9\u51FA\u7684\u7C89\u7EA2\u566A\u58F0\u8FD1\u4F3C\u529F\u7387\u56FE</p><ul><li>\u5176\u529F\u7387\u4EE510dB/Decade\uFF0810\u5206\u8D1D\u6BCF\u5341\u500D\u9891\uFF09\u8870\u51CF</li><li>\u4E5F\u53EF\u4EE5\u8BF4\u62103dB/Octave\uFF083\u5206\u8D1D\u6BCF\u4E8C\u500D\u9891\uFF09</li></ul><p><img src="'+n+'" alt=""></p><p>\u5F00\u542FSlope\u540E\u7684Peak Hold\u66F2\u7EBF\uFF0C\u80FD\u660E\u663E\u53D1\u73B0\u8D85\u9AD8\u9891\u6BB5\u7684\u201C\u6709\u6548\u7535\u5E73\u201D\u53D1\u751F\u4E86\u503E\u659C</p>',45),h=[p];function g(c,u,_,m,v,k){return t(),o("div",null,h)}const H=l(d,[["render",g]]);export{f as __pageData,H as default};
